{
  "family": "Fries-, Photo-Fries, and Anionic Ortho-Fries Rearrangement",
  "candidate": {
    "substrate_smiles": [
      "CC(=O)Oc1ccccc1"
    ],
    "product_smiles": [
      "CC(=O)c1ccccc1O",
      "CC(=O)c1cccc(O)c1"
    ],
    "optional_reagent_smiles": [
      "[Al+3].[Cl-].[Cl-].[Cl-]"
    ],
    "rationale": "The Fries rearrangement of phenyl acetate is the quintessential textbook example of this reaction family. It clearly demonstrates the migration of an acyl group from a phenolic oxygen to the ortho and para positions of the aromatic ring under Lewis acid catalysis (AlCl3). The substrate and products are simple, acyclic where possible, and contain the core functional group transformation without extraneous complexity.",
    "collision_avoidance_note": "This example uses the simplest possible phenyl ester (phenyl acetate) to avoid complex aromatic systems that could overlap with other named reactions involving arenes. The acyl group is a simple acetyl group. The reaction is a rearrangement, not a substitution or coupling, which helps distinguish it from reactions like Friedel-Crafts acylation, although the mechanism has similarities. The focus on the specific O-to-C acyl migration is key."
  }
}
